package maven.core.org.apache.karaf.maven.command;

@ Command ( scope = "maven" , name = "summary" , description = "Maven configuration summary." ) @ Service public class SummaryCommand extends MavenSecuritySupport { @ Option ( name = "-p" , aliases = { "--property-ids" } , description = "Use PID property identifiers instead of their names" , required = false , multiValued = false ) boolean propertyIds ; @ Option ( name = "-s" , aliases = { "--source" } , description = "Adds information about where the value is configured" , required = false , multiValued = false ) boolean source ; @ Option ( name = "-d" , aliases = { "--description" } , description = "Adds description of Maven configuration options" , required = false , multiValued = false ) boolean description ; @ Override protected void doAction ( String prefix , Dictionary < String , Object > config ) throws Exception { ShellTable table = new ShellTable ( ) ; table . column ( "Option" ) ; table . column ( "Value" ) ; if ( source ) { table . column ( "Source" ) ; } if ( description ) { table . column ( "Description" ) ; } addRow ( table , propertyIds ? PROPERTY_LOCAL_REPOSITORY : "Local repository" , localRepository , "Maven repository to store artifacts resolved in *remote repositories*" ) ; addRow ( table , propertyIds ? PROPERTY_SETTINGS_FILE : "Settings file" , settings , "Settings file that may contain configuration of additional repositories, http proxies and mirrors" ) ; addRow ( table , propertyIds ? PROPERTY_SECURITY_FILE : "Security settings file" , securitySettings , "Settings file that contain (or relocates to) master Maven password" ) ; if ( showPasswords ) { addRow ( table , propertyIds ? "<master>" : "Master password" , new SourceAnd < String > ( securitySettings . source , masterPassword ) , "Master password used to decrypt proxy and server passwords" ) ; } SourceAnd < String > updatePolicy = updatePolicy ( ( String ) config . get ( prefix + PROPERTY_GLOBAL_UPDATE_POLICY ) ) ; addRow ( table , propertyIds ? PROPERTY_GLOBAL_UPDATE_POLICY : "Global update policy" , updatePolicy , "Overrides update policy specified at repository level (if specified)" ) ; SourceAnd < String > checksumPolicy = checksumPolicy ( ( String ) config . get ( prefix + PROPERTY_GLOBAL_CHECKSUM_POLICY ) ) ; addRow ( table , propertyIds ? PROPERTY_GLOBAL_CHECKSUM_POLICY : "Global checksum policy" , checksumPolicy , "Checksum policy for all repositories" ) ; String updateReleasesProperty = ( String ) config . get ( prefix + PROPERTY_UPDATE_RELEASES ) ; boolean updateReleases = false ; String sourceInfo = String . format ( PATTERN_PID_PROPERTY , PID , prefix + PROPERTY_UPDATE_RELEASES ) ; if ( updateReleasesProperty == null ) { sourceInfo = "Default \"false\"" ; } else { updateReleases = "true" . equals ( updateReleasesProperty ) ; } addRow ( table , propertyIds ? PROPERTY_UPDATE_RELEASES : "Update releases" , new SourceAnd < Boolean > ( sourceInfo , updateReleases ) , "Whether to download non-SNAPSHOT artifacts according to update policy" ) ; String requireConfigAdminProperty = context . getProperty ( prefix + REQUIRE_CONFIG_ADMIN_CONFIG ) ; boolean requireConfigAdmin = requireConfigAdminProperty != null ; sourceInfo = "Default \"false\"" ; if ( requireConfigAdmin ) { sourceInfo = "BundleContext property (" + prefix + REQUIRE_CONFIG_ADMIN_CONFIG + ")" ; } addRow ( table , propertyIds ? REQUIRE_CONFIG_ADMIN_CONFIG : "Require Config Admin" , new SourceAnd < Boolean > ( sourceInfo , requireConfigAdmin ) , "Whether MavenResolver service is registered ONLY with proper " + PID + " PID configuration" ) ; String useFallbackRepositoriesProperty = ( String ) config . get ( prefix + PROPERTY_USE_FALLBACK_REPOSITORIES ) ; boolean useFallbackRepositories = Boolean . parseBoolean ( useFallbackRepositoriesProperty ) ; sourceInfo = "Default \"false\"" ; if ( useFallbackRepositoriesProperty != null ) { sourceInfo = String . format ( PATTERN_PID_PROPERTY , PID , prefix + PROPERTY_USE_FALLBACK_REPOSITORIES ) ; } addRow ( table , propertyIds ? PROPERTY_USE_FALLBACK_REPOSITORIES : "Use fallback repository" , new SourceAnd < Boolean > ( sourceInfo , useFallbackRepositories ) , "Whether Maven Central is used as implicit, additional remote repository" ) ; String offlineProperty = ( String ) config . get ( prefix + PROPERTY_OFFLINE ) ; boolean offline = Boolean . parseBoolean ( offlineProperty ) ; sourceInfo = "Default \"false\"" ; if ( offlineProperty != null ) { sourceInfo = String . format ( PATTERN_PID_PROPERTY , PID , prefix + PROPERTY_OFFLINE ) ; } addRow ( table , propertyIds ? PROPERTY_OFFLINE : "Offline mode" , new SourceAnd < Boolean > ( sourceInfo , offline ) , "Disables access to external remote repositories (file:// based ones are still used)" ) ; String certificateCheckProperty = ( String ) config . get ( prefix + PROPERTY_CERTIFICATE_CHECK ) ; boolean certificateCheck = Boolean . parseBoolean ( certificateCheckProperty ) ; sourceInfo = "Default \"false\"" ; if ( certificateCheckProperty != null ) { sourceInfo = String . format ( PATTERN_PID_PROPERTY , PID , prefix + PROPERTY_CERTIFICATE_CHECK ) ; } addRow ( table , propertyIds ? PROPERTY_CERTIFICATE_CHECK : "SSL/TLS certificate check" , new SourceAnd < Boolean > ( sourceInfo , certificateCheck ) , "Turns on server certificate validation for HTTPS remote repositories" ) ; MavenRepositoryURL [ ] remoteRepositories = repositories ( config , true ) ; boolean first = true ; for ( MavenRepositoryURL url : remoteRepositories ) { addRow ( table , first ? ( propertyIds ? PROPERTY_REPOSITORIES : "Remote repositories" ) : "" , new SourceAnd < String > ( url . getFrom ( ) . getSource ( ) , url . getURL ( ) . toString ( ) ) , first ? "Remote repositories where artifacts are being resolved if not found locally" : "" ) ; first = false ; } MavenRepositoryURL [ ] defaultRepositories = repositories ( config , false ) ; first = true ; for ( MavenRepositoryURL url : defaultRepositories ) { addRow ( table , first ? ( propertyIds ? PROPERTY_DEFAULT_REPOSITORIES : "Default repositories" ) : "" , new SourceAnd < String > ( url . getFrom ( ) . getSource ( ) , url . getURL ( ) . toString ( ) ) , first ? "Repositories where artifacts are looked up before trying remote resolution" : "" ) ; first = false ; } if ( mavenSettings != null && mavenSettings . getProxies ( ) != null ) { first = true ; for ( Proxy proxy : mavenSettings . getProxies ( ) ) { String value = String . format ( "%s:%s" , proxy . getHost ( ) , proxy . getPort ( ) ) ; addRow ( table , first ? ( propertyIds ? "<proxies>" : "HTTP proxies" ) : "" , new SourceAnd < String > ( MavenRepositoryURL . FROM . SETTINGS . getSource ( ) , value ) , first ? "Maven HTTP proxies" : "" ) ; first = false ; } } System . out . println ( ) ; table . print ( System . out ) ; System . out . println ( ) ; } private < T > void addRow ( ShellTable table , String label , SourceAnd < T > value , String descriptionText ) { Row row = table . addRow ( ) ; row . addContent ( label , value . val ( ) ) ; if ( source ) { row . addContent ( value . source ) ; } if ( description ) { row . addContent ( descriptionText ) ; } } }